def valid_date(date):
    """Verilen tarih dizesini doğrular. Tarih mm-dd-yyyy formatında olmalı ve belirtilen kurallara uymalıdır."""
    if not date:
        return False  # Tarih dizesi boşsa hemen False döndür

    parts = date.split('-')
    if len(parts) != 3:
        return False  # Parçaların sayısı 3 değilse hemen False döndür

    try:
        month = int(parts[0])
        day = int(parts[1])
        year = int(parts[2])
    except ValueError:
        return False  # Herhangi bir parçanın tamsayıya dönüştürülmesi başarısız olursa False döndür

    if not (1 <= month <= 12):
        return False  # Ay 1-12 aralığında değilse False döndür

    # Gün sayısını ay göre kontrol et
    if month in [1, 3, 5, 7, 8, 10, 12]:
        if not (1 <= day <= 31):
            return False  # 31 gün olan aylar için gün 1-31 aralığında olmalı
    elif month in [4, 6, 9, 11]:
        if not (1 <= day <= 30):
            return False  # 30 gün olan aylar için gün 1-30 aralığında olmalı
    elif month == 2:
        if not (1 <= day <= 29):
            return False  # Şubat için gün 1-29 aralığında olmalı

    return True  # Tüm kurallar sağlanıyorsa True döndür
